import{_ as n,o as e,c as t,a2 as s}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"AI Agent 测试可量化方案分析","description":"","frontmatter":{"title":"AI Agent 测试可量化方案分析"},"headers":[],"relativePath":"research/ai-agent-quantification.md","filePath":"research/ai-agent-quantification.md","lastUpdated":1784762596000}'),o={name:"research/ai-agent-quantification.md"};function i(l,a,p,r,g,c){return e(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="ai-agent-测试可量化方案分析" tabindex="-1">AI Agent 测试可量化方案分析 <a class="header-anchor" href="#ai-agent-测试可量化方案分析" aria-label="Permalink to &quot;AI Agent 测试可量化方案分析&quot;">​</a></h1><p>回答&quot;AI Agent 测试岗位要求的可量化是否就是可观测性工具&quot;这一问题，并梳理完整方案。</p><h2 id="三层量化体系ai-agent-的可量化通常分三层-观测工具主要集中在中间层" tabindex="-1">三层量化体系AI Agent 的可量化通常分三层，观测工具主要集中在中间层： <a class="header-anchor" href="#三层量化体系ai-agent-的可量化通常分三层-观测工具主要集中在中间层" aria-label="Permalink to &quot;三层量化体系AI Agent 的可量化通常分三层，观测工具主要集中在中间层：&quot;">​</a></h2><p>层次 量化什么 代表工具/方案 业务指标层 任务完成率、用户满意度、ROI、成本/Task 自建数据管道 + BI 看板 质量评估层 准确率、幻觉率、忠实度、安全性 DeepEval、Langfuse、Phoenix、Promptfoo 执行可观测层 延迟、Token 消耗、错误率、调用链 Langfuse、Phoenix、OpenTelemetry、MLflow</p><h2 id="可观测性工具能覆盖的量化维度这批工具确实能解决大部分可量化需求" tabindex="-1">可观测性工具能覆盖的量化维度这批工具确实能解决大部分可量化需求： <a class="header-anchor" href="#可观测性工具能覆盖的量化维度这批工具确实能解决大部分可量化需求" aria-label="Permalink to &quot;可观测性工具能覆盖的量化维度这批工具确实能解决大部分可量化需求：&quot;">​</a></h2><p><strong>Langfuse</strong> 能做的：</p><ul><li>每次 Agent 调用的完整链路追踪（推理步骤、工具调用、检索命中）- Token 成本拆解（按模型/用户/会话维度）- LLM-as-Judge 自动评分（幻觉/相关性/毒性）- 评分结果挂到具体 Trace 上，做&quot;按低分过滤 → 打开 Trace 定位根因&quot;的闭环<strong>Arize Phoenix</strong> 能做的：</li><li>RAG 检索质量可视化（检索到的文档是否相关）- 嵌入漂移检测（模型行为是否随时间劣化）- 幻觉自动检测<strong>DeepEval</strong> 能做的：</li><li>研究级评估指标：忠实度（Faithfulness）、答案相关性（Answer Relevancy）、上下文召回（Contextual Recall）- 这些指标可以直接量化 Agent 输出质量## 观测工具覆盖不到的部分&quot;可量化&quot;还有几个维度是这批工具本身不直接解决的：</li></ul><h3 id="_1-agent-任务成功率-端到端-agent-的核心能力是-完成一个多步任务-。观测工具能告诉你每一步发生了什么-但不直接告诉你任务是否成功。需要一个评估数据集-判定逻辑" tabindex="-1">1. Agent 任务成功率（端到端）Agent 的核心能力是&quot;完成一个多步任务&quot;。观测工具能告诉你每一步发生了什么，但<strong>不直接告诉你任务是否成功</strong>。需要一个<strong>评估数据集 + 判定逻辑</strong>： <a class="header-anchor" href="#_1-agent-任务成功率-端到端-agent-的核心能力是-完成一个多步任务-。观测工具能告诉你每一步发生了什么-但不直接告诉你任务是否成功。需要一个评估数据集-判定逻辑" aria-label="Permalink to &quot;1. Agent 任务成功率（端到端）Agent 的核心能力是&quot;完成一个多步任务&quot;。观测工具能告诉你每一步发生了什么，但**不直接告诉你任务是否成功**。需要一个**评估数据集 + 判定逻辑**：&quot;">​</a></h3><ul><li>定义一个测试集（如 100 个用户场景）- 让 Agent 执行，捕获最终输出- 用 LLM-as-Judge 或人工标注判定&quot;任务是否完成&quot;- 这就是 <strong>Braintrust、LangSmith</strong> 更侧重的方向——离线评估实验### 2. 行为基准与回归测试用固定数据集定期跑一遍，对比评分变化。这需要：</li><li><strong>Promptfoo</strong>（开源）：专门做 Prompt 和模型的 A/B 对比测试- 自建 CI/CD 中的评估流水线（每次部署前跑评估集）### 3. 多 Agent 协作评估当多个 Agent 协作时，需要评估&quot;协调效率&quot;——比如 Agent A 传递给 Agent B 的信息是否完整、是否有冗余回路。这需要自定义的图结构评估，没有现成工具直接支持。</li></ul><h3 id="_4-业务对齐指标-这个-agent-替代了客服后-工单解决率提升了多少-——这需要把-agent-的-trace-数据与业务系统-crm、工单系统-的数据关联-观测工具提供的是-trace-数据源-但关联分析通常需要自建。" tabindex="-1">4. 业务对齐指标&quot;这个 Agent 替代了客服后，工单解决率提升了多少？&quot;——这需要把 Agent 的 Trace 数据与业务系统（CRM、工单系统）的数据关联，观测工具提供的是 Trace 数据源，但关联分析通常需要自建。 <a class="header-anchor" href="#_4-业务对齐指标-这个-agent-替代了客服后-工单解决率提升了多少-——这需要把-agent-的-trace-数据与业务系统-crm、工单系统-的数据关联-观测工具提供的是-trace-数据源-但关联分析通常需要自建。" aria-label="Permalink to &quot;4. 业务对齐指标&quot;这个 Agent 替代了客服后，工单解决率提升了多少？&quot;——这需要把 Agent 的 Trace 数据与业务系统（CRM、工单系统）的数据关联，观测工具提供的是 Trace 数据源，但关联分析通常需要自建。&quot;">​</a></h3><h2 id="完整可量化方案结合-ai-agent-可观测性设计-完整的可量化方案应该是" tabindex="-1">完整可量化方案结合 AI Agent 可观测性设计，完整的可量化方案应该是： <a class="header-anchor" href="#完整可量化方案结合-ai-agent-可观测性设计-完整的可量化方案应该是" aria-label="Permalink to &quot;完整可量化方案结合 AI Agent 可观测性设计，完整的可量化方案应该是：&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              业务指标（自建 BI/看板）              │</span></span>
<span class="line"><span>│   任务完成率 / 用户满意度 / 成本/Task / ROI       │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│              质量评估层                           │</span></span>
<span class="line"><span>│   DeepEval 指标 + Langfuse LLM-as-Judge         │</span></span>
<span class="line"><span>│   + 离线评测数据集（Brainsrust/Promptfoo）        │</span></span>
<span class="line"><span>│   + RedTeam 安全测试                             │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│              可观测性层（插件 + 现有工具）         │</span></span>
<span class="line"><span>│   OpenTelemetry 追踪 → Langfuse/Phoenix 后端     │</span></span>
<span class="line"><span>│   Span 属性：Token / 成本 / 安全裁决 / 工具调用    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────┘</span></span>
<span class="line"><span>\`\`\`## 总结观测工具（Langfuse、Phoenix、DeepEval）是&quot;可量化&quot;的基础设施，负责追踪和打分。但要真正让 AI Agent 可量化，还需要在它们之上加一层**评估数据集驱动的测试流水线**（Promptfoo、自建评测集）和**业务指标关联**（Trace 数据 + 业务系统）。这一套组合才是 AI Agent 测试岗位要求的&quot;可量化&quot;全貌。</span></span>
<span class="line"><span>生成时间：2026-07-22</span></span></code></pre></div>`,12)])])}const A=n(o,[["render",i]]);export{h as __pageData,A as default};
